import React, { useMemo } from 'react';

const MemoizedComponent = ({ objects }) => {
  const memoizedValue = useMemo(() => {
    const result = objects.map((object, index) => {
      return object.name;
    });
    return result.join(', ');
  }, [
    'objects',
  ]);
  return <div>{memoizedValue}</div>;
};

export default MemoizedComponent;

